var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"여전히 우리에겐 닿지도 못할 공격이군요.","JPN":"無駄な攻撃です。","ENG":"Your attacks still cannot reach us.","TWN":"你的攻擊對我們起不了作用的。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"인간이란 홀로 나약한 존재입니다.","JPN":"人間とは一人では弱い存在です。","ENG":"Humans are weak beings when they are alone.","TWN":"人類這種個體是孤獨而脆弱的存在。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"하지만 우리가 모인다면 다릅니다. 우리는 하나이자 여럿. 더 완전해질 수 있습니다.","JPN":"ですが、私たちが集まると話が違う。私たちは一人でありながら多数。さらに完全となれるのです。","ENG":"But when we gather, it becomes a different story. We are one and many. We can become more complete.","TWN":"但是如果聚在一起就另當別論了。我們既是一體，也是多個個體，我們可以變得更加完整。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"당신이 바라는 어둠의 정화도, 세상의 평화도 모두 가져올 수 있단 말입니다!","JPN":"あなたが望んでいる闇の浄化も、世界の平和もすべて成し遂げられるのです！","ENG":"The purification of darkness and world peace you desire... we can make them both happen!","TWN":"你所期望的淨化黑暗和世界和平都能實現！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"날 삼킨다고 해서, 달라지는 게 있을 것 같나?","JPN":"私を飲み込んで、変わるものがあると思うか？","ENG":"Do you think anything will change if you swallow me?","TWN":"你以為吞噬掉我，就能改變什麼嗎？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"침식체는 절대 자신의 망집을 해소할 수 없다.","JPN":"侵食体は決して自らのの妄執を解消することができない。","ENG":"C.O.s can never resolve their obsessions.","TWN":"侵蝕體永遠被困在自己的妄念裡。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"날 삼킨 뒤엔 영원히 이루지 못할 소망을 이루기 위해 떠돌아다닐 것이 뻔하지.","JPN":"私を飲み込んだところで、叶えられない願いを叶えるために永遠を彷徨うことだろう。","ENG":"After you swallow me, you will wander about again trying to fulfill a wish that will never come true.","TWN":"吞噬我之後，你將永遠為無法實現的願望而徘徊。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그럴 리가 없지 않습니까? 당신이 바라는 것은 모두 우리에게 있습니다.","JPN":"そんなはずはありません。あなたの望むものは、すべて私たちが持っています。","ENG":"Do you really think so? We have everything you desire.","TWN":"怎麼可能？你想要的一切我們都有。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"내가 원하는 게 너에게 있을 리가 없다. 침식체.","JPN":"私の望むものを、君は持ち合わせていない、侵食体。","ENG":"I'm certain that you cannot give me what I desire, C.O.","TWN":"我想要的東西你不可能有，侵蝕體。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"우리는 영원히 함께 싸우겠다고 맹세했습니다.","JPN":"私たちは永遠に共に戦うと誓いました。","ENG":"We vowed to fight alongside each other for an eternity.","TWN":"我們發誓要永遠並肩作戰。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그 긴 세월동안, 우리는 당신을 맞이하기 위해 모든 것을 준비했어요.","JPN":"この長い間、私たちはあなたを迎え入れるためにすべてを用意してきました。","ENG":"During those long years, we have prepared everything to welcome you in.","TWN":"在那漫長的歲月裡，我們做好一切準備為要迎接你。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"이제야 우리가 다시 만났는데…… 왜 이런 어리석은 선택을 하는 겁니까!","JPN":"やっと私たちが再会できたというのに……どうしてこんな愚かな選択をするのですか！","ENG":"And now, we finally meet... But why are you making such a foolish choice?!","TWN":"我們好不容易才重逢……為什麼要做出這樣愚蠢的選擇！"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"내 기억을 갖고 있다면서 그것조차 깨닫지 못했나?","JPN":"私の記憶を持っていると言っているのに、それすらわからないのか？","ENG":"You say you have my memories, but you haven't figured out the reason?","TWN":"你說你擁有我的記憶，卻連這點都沒意識到嗎？"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그때나 지금이나 달라진 것이 없기 때문이다.","JPN":"あの時も今も、何も変わっていないからだ。","ENG":"It's because nothing has changed since then.","TWN":"那時候和現在沒有任何不同。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그때도, 지금도…… 모든 걸 잃었다는 점은 변하지 않았어.","JPN":"あの時も、今も……すべてを失ったということは変わっていない。","ENG":"The fact that I've lost everything doesn't change... Not then, not now.","TWN":"無論是那時，或是現在…我始終是失去一切的人。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"텅 비어버린 날 채우기 위해선, 침식체의 망집 따위로는 부족할 거다.","JPN":"空っぽになってしまった自分を満たすためには、侵食体の妄執などでは足りないだろう。","ENG":"And to fill this emptiness inside me, a C.O.'s obsession will not be enough.","TWN":"侵蝕體的妄念，是遠遠不夠拿來慰藉這份空虛的。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"세상의 모든 걸 삼켜 내 것으로 만들어야 할 테니까.","JPN":"世界のすべてを飲み込み、我が物にしなければいけないだろうからな。","ENG":"I will need to consume the world and make it my own to do that.","TWN":"你得吞得下整個世界才行。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"텅 비워버린 당신을 채우기 위해서라면, 우린 기꺼이 세상을 삼킬 준비가 되어 있습니다.","JPN":"空っぽになったあなたを満たすためなら、私たちは喜んで世界を飲み込む準備ができています。","ENG":"If it is to fill the emptiness inside you, we are willing to consume the entire world.","TWN":"如果是為了填補你的空虛，我們願意吞噬整個世界。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"침식체의 헛소리는 더 들어줄 가치도 없다.","JPN":"侵食体の戯言など、もう聞いてやる価値もない。","ENG":"Your nonsense is not worth listening to anymore, C.O.","TWN":"你的這些胡言亂語再聽下去也沒意義。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"물론, 이번에도 무언가 잃어야 될 지도 몰라.","JPN":"もちろん、今度も何かを失うことになるかもしれない。","ENG":"Of course, I might lose something this time as well.","TWN":"當然，我很清楚這次也可能會失去些什麼。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"하지만 다행스럽게도, 나는 이제 목숨 말고는 잃을 것이 없다.","JPN":"だが幸い、私にはもう自分の命しか失うものがないのだ。","ENG":"But fortunately, I now have nothing to lose but my life.","TWN":"但幸運的是，我現在能失去的，就只有這條命。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"길동무가 되는 한이 있더라도…….","JPN":"道連れになることがあっても……","ENG":"Even if I have to take you down with me...","TWN":"就算是同歸於盡……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"반드시…… 정화해주마.","JPN":"必ず……浄化してやる。","ENG":"I will... purify you.","TWN":"也一定……要淨化你。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};